        "exhibition.seq_title": "The Main <span style=\"color: var(--hall-gold);\">Galleries</span>",
        "exhibition.hall1_title": "Dawn & Old Kingdom",
        "exhibition.hall1_desc": "Explore the origins of society and beliefs. Witness the mysterious <strong>Reserve Head</strong> and the protective <strong>Ptah-Sokar-Osiris figure</strong> from the age of the Pyramid Builders.",
        "exhibition.hall2_title": "The Middle Kingdom",
        "exhibition.hall2_desc": "A period of cultural renaissance. Witness the majestic <strong>Statue of Senusret I</strong> and explore the daily lives, royal power, and spirituality of a reunified Egypt.",
        "exhibition.hall3_title": "The New Kingdom",
        "exhibition.hall3_desc": "The golden age of empire. Witness the <strong>Victory Stele</strong>, the exquisite <strong>Shabti Box</strong>, and the <strong>Papyrus of Ani</strong> alongside the warrior statues of <strong>Thutmose III</strong>.",
        "exhibition.hall4_title": "Late & Greco-Roman",
        "exhibition.hall4_desc": "The transformation of Egypt through the Third Intermediate Period, culminating in the cultural synthesis of the <strong>Greco-Roman</strong> era and the <strong>Pompey's Pillar</strong>.",
        "exhibition.ramses_label": "The Living Sun King",
        "exhibition.ramses_title": "Colossus of <br>Ramses II",
        "exhibition.ramses_desc": "Standing 11 meters tall and weighing 83 tons, the 3,200-year-old red granite statue of Ramses II welcomes every visitor. Standing exactly where the sun rays illuminate it twice a year.",
        "exhibition.ramses_atrium": "The Great Atrium",
        "exhibition.guardians_label": "Atrium Masterpieces",
        "exhibition.guardians_title": "Guardians of <br><span style=\"color: var(--hall-gold);\">The Great Hall</span>",
        "exhibition.guardians_desc": "Beyond the colossal Ramses, the Grand Hall houses treasures that define the spiritual and military history of Egypt.",
        "exhibition.ptolemaic_title": "The Ptolemaic Royal Pair",
        "exhibition.ptolemaic_desc": "These monumental colossi of a Ptolemaic King and Queen were retrieved from the depths of the Mediterranean. Standing side-by-side in the Grand Hall, they guard the entrance with a unique blend of Hellenistic artistry and ancient Egyptian divine authority.",
        "exhibition.ptolemaic_badge1": "Ptolemaic Period",
        "exhibition.ptolemaic_badge2": "5-Meter Colossi",
