            // ── About Page ──

            "about.hero_title": "About the Grand Egyptian Museum",
            "about.history_title_1": "A Journey Through Time: The ",
            "about.history_title_2": "Story of the GEM",
            "about.history_desc": "The Grand Egyptian Museum (GEM) is the culmination of a vision to create a world-class institution dedicated to the preservation and display of Egypt's rich Pharaonic heritage.",

            "about.tl1_title": "The Vision",
            "about.tl1_year": "Early 2000s",
            "about.tl1_text": "The idea for a new, modern museum to house Egypt's vast collection of ancient artifacts was born, aiming to provide a worthy home for treasures like those of Tutankhamun.",
            "about.tl2_title": "Foundation Stone",
            "about.tl2_year": "2002",
            "about.tl2_text": "The foundation stone of the Grand Egyptian Museum was officially laid by President Hosni Mubarak, marking the dawn of the most ambitious cultural project of the 21st century.",
            "about.tl3_title": "International Design Competition",
            "about.tl3_year": "2003",
            "about.tl3_text_1": "An international competition was held in <span class=\"highlight-date\">2003</span> to select an architectural design. The winning entry by <span class=\"gold-text-span\">Heneghan Peng Architects</span> was chosen for its modern interpretation of ancient Egyptian themes.",
            "about.tl4_title": "Construction Begins",
            "about.tl4_year": "2005",
            "about.tl4_text": "The monumental task of building the world's largest archaeological museum began in <span class=\"highlight-date\">2005</span> on the Giza plateau, overlooking the majestic pyramids.",
            "about.tl5_title": "Conservation Excellence",
            "about.tl5_year": "2010",
            "about.tl5_text": "The <span class=\"gold-text-span\">GEM Conservation Center</span> officially opened in <span class=\"highlight-date\">2010</span>. It is one of the largest and most advanced in the world, preserving over <span class=\"highlight-date\">50,000</span> artifacts.",
            "about.tl6_title": "Ramses II's Arrival",
            "about.tl6_year": "2018",
            "about.tl6_text": "The 3,200-year-old colossus of Ramses II was moved to its permanent home in the museum's grand entrance hall in a spectacular engineering feat.",
            "about.tl7_title": "The Solar Boat's Journey",
            "about.tl7_year": "2021",
            "about.tl7_text": "The ancient Khufu Solar Boat was painstakingly transported from its site near the Great Pyramid to its dedicated hall within the GEM.",
            "about.tl8_title": "Tutankhamun's Treasures Arrive",
            "about.tl8_year": "2022",
            "about.tl8_text": "The meticulous transfer of over <span class=\"highlight-date\">5,000</span> artifacts from the tomb of the Golden King Tutankhamun was completed, preparing them for their first-ever unified display.",
            "about.tl9_title": "Trial Operations",
            "about.tl9_year": "2024",
            "about.tl9_text": "The museum launched limited trial tours, inviting the world to experience the majestic Grand Staircase and the commercial district for the first time.",
            "about.tl10_title": "The Grand Opening",
            "about.tl10_year": "2026",
            "about.tl10_text": "A historic celebration marks the official inauguration of the world's largest archaeological museum, housing the full collection of King Tutankhamun.",

            "about.arch_title_1": "A Modern Marvel: The ",
            "about.arch_title_2": "Architectural Splendor",
            "about.arch_title_3": " of the GEM",
            "about.arch_desc": "The museum's design is a testament to architectural innovation, blending seamlessly with its historic surroundings while making a bold contemporary statement.",

            "about.stair_title_1": "The ",
            "about.stair_title_2": "Grand Staircase",
            "about.stair_desc": "Ascend through the history of ancient Egypt on our monumental Grand Staircase. Spanning four levels, this architectural centerpiece showcases the chronological progression of Pharaonic art, leading you towards the breathtaking view of the Pyramids.",
            "about.stair_spec1": "<strong>64 meters</strong> of panoramic history",
            "about.stair_spec2": "<strong>87 statues</strong> and architectural fragments",
            "about.stair_spec3": "<strong>4 distinct eras</strong> from Old Kingdom to Late Period",

            "about.team_title_1": "The Guardians of ",
            "about.team_title_2": "Heritage",
            "about.team_desc": "Meet the experts dedicated to preserving Egypt's legacy.",
            "about.team_r1": "Head of Conservation",
            "about.team_r2": "Lead Archaeologist",
            "about.team_r3": "CEO",

            "about.future_title_1": "The Future is ",
            "about.future_title_2": "Tutora",
            "about.future_desc": "We are redefining the museum experience through digital innovation. Our AI-driven ecosystem bridges the gap between ancient history and modern audiences.",
            "about.future_ai1_title": "AI Chatbot",
            "about.future_ai1_desc": "A 24/7 personal guide that answers any historical question in real-time.",
            "about.future_ai2_title": "Artifact Identifier",
            "about.future_ai2_desc": "Scan any artifact with your phone to unlock deep-dive historical context.",
            "about.future_ai3_title": "3D Voice Storytelling",
            "about.future_ai3_desc": "Immersive audio-visual journeys through photorealistic ancient reconstructions.",

            "about.sust_title_1": "Sustainability & ",
            "about.sust_title_2": "Future-Proofing",
            "about.sust_desc": "The Grand Egyptian Museum is built to last centuries, not just for its monumental architecture, but through our commitment to environmental stewardship and digital preservation.",
            "about.sust_f1_title": "Solar Energy Integration",
            "about.sust_f1_desc": "The museum utilizes state-of-the-art photovoltaic panels to power its climate-controlled galleries.",
            "about.sust_f2_title": "Water Conservation",
            "about.sust_f2_desc": "Innovative desert landscaping and recycling systems reduce our ecological footprint.",

            "about.part_title_1": "Our Global ",
            "about.part_title_2": "Partners",
            "about.part_desc": "Collaborating with the world's leading institutions to bring history to life.",

            "about.cta_title_1": "Ready to ",
            "about.cta_title_2": "Journey Through Time?",
            "about.cta_btn": "Book Your Experience Now",

            "about.miss_title_1": "Our Commitment to ",
            "about.miss_title_2": "Heritage and Humanity",
